import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import { ProjectSelector } from './ProjectSelector';
import type { TimeEntry } from '../types';

interface EditTimeEntryModalProps {
  entry: TimeEntry;
  onClose: () => void;
}

/**
 * EditTimeEntryModal Component
 * Modal dialog for editing existing time entries
 */
export function EditTimeEntryModal({ entry, onClose }: EditTimeEntryModalProps) {
  const { updateEntry } = useTimeTrackingStore();

  const [description, setDescription] = useState(entry.description);
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [projectId, setProjectId] = useState<string | null>(entry.projectId || null);
  const [notes, setNotes] = useState(entry.notes || '');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    // Format times for datetime-local input
    const formatDateTimeLocal = (isoString: string) => {
      const date = new Date(isoString);
      return date.toISOString().slice(0, 16);
    };

    setStartTime(formatDateTimeLocal(entry.startTime));
    if (entry.endTime) {
      setEndTime(formatDateTimeLocal(entry.endTime));
    }
  }, [entry]);

  const handleSave = async () => {
    setError('');

    // Validation
    if (!description.trim()) {
      setError('Description is required');
      return;
    }

    if (!startTime) {
      setError('Start time is required');
      return;
    }

    if (!endTime) {
      setError('End time is required');
      return;
    }

    const startDate = new Date(startTime);
    const endDate = new Date(endTime);

    if (endDate <= startDate) {
      setError('End time must be after start time');
      return;
    }

    setSaving(true);
    try {
      // Calculate new duration
      const newDuration = Math.floor((endDate.getTime() - startDate.getTime()) / 1000);

      await updateEntry(entry.id, {
        description: description.trim(),
        startTime: startDate.toISOString(),
        endTime: endDate.toISOString(),
        duration: newDuration,
        projectId: projectId || undefined,
        notes: notes.trim() || undefined
      });

      onClose();
    } catch (err) {
      console.error('Failed to update entry:', err);
      setError('Failed to save changes. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onClose();
    } else if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      handleSave();
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <div
        className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark shadow-xl max-w-md w-full"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={handleKeyDown}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-border-light dark:border-border-dark">
          <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
            Edit Time Entry
          </h2>
          <button
            onClick={onClose}
            className="p-1 rounded-buttonhover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label="Close modal"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Body */}
        <div className="p-6 space-y-4">
          {error && (
            <div className="px-4 py-3 bg-status-error/10 border border-status-error/20 rounded-buttontext-status-error text-sm">
              {error}
            </div>
          )}

          {/* Description */}
          <div>
            <label
              htmlFor="description"
              className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
            >
              Description
            </label>
            <input
              id="description"
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
              placeholder="What did you work on?"
            />
          </div>

          {/* Start Time */}
          <div>
            <label
              htmlFor="startTime"
              className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
            >
              Start Time
            </label>
            <input
              id="startTime"
              type="datetime-local"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* End Time */}
          <div>
            <label
              htmlFor="endTime"
              className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
            >
              End Time
            </label>
            <input
              id="endTime"
              type="datetime-local"
              value={endTime}
              onChange={(e) => setEndTime(e.target.value)}
              className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* Project */}
          <div>
            <label
              htmlFor="project"
              className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
            >
              Project
            </label>
            <ProjectSelector
              value={projectId}
              onChange={setProjectId}
              placeholder="No Project"
              showNoProject={true}
            />
          </div>

          {/* Notes */}
          <div>
            <label
              htmlFor="notes"
              className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
            >
              Notes (Optional)
            </label>
            <textarea
              id="notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={3}
              className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary resize-none"
              placeholder="Add additional details about this time entry..."
            />
          </div>

          {/* Duration Preview */}
          {startTime && endTime && (
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Duration:{' '}
              <span className="font-mono font-semibold text-accent-magenta dark:text-accent-cyan">
                {(() => {
                  const start = new Date(startTime).getTime();
                  const end = new Date(endTime).getTime();
                  const durationSeconds = Math.floor((end - start) / 1000);
                  const hours = Math.floor(durationSeconds / 3600);
                  const minutes = Math.floor((durationSeconds % 3600) / 60);
                  return `${hours}h ${minutes.toString().padStart(2, '0')}m`;
                })()}
              </span>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-border-light dark:border-border-dark">
          <button
            onClick={onClose}
            disabled={saving}
            className="px-4 py-2 text-sm font-medium text-text-light-primary dark:text-text-dark-primary bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonhover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            className="px-4 py-2 text-sm font-medium text-white dark:text-dark-background bg-accent-magenta dark:bg-accent-cyan rounded-buttonhover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

