                <input
                  id="durationMinutes"
                  type="number"
                  min="0"
                  max="59"
                  value={durationMinutes}
                  onChange={(e) => setDurationMinutes(e.target.value)}
                  className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
            </div>
          )}

          {/* Duration Preview */}
          {duration && duration.seconds > 0 && (
            <div className="px-4 py-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-buttonborder border-border-light dark:border-border-dark">
