            className="px-4 py-2 text-sm font-medium text-text-light-primary dark:text-text-dark-primary bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonhover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth disabled:opacity-50"
          >
            Cancel
