                      {event.recurrence && '🔁 '}{event.title}
                    </div>
                    <div className="flex items-center gap-3 mt-1 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      {event.isAllDay ? (
                        <span>All day</span>
                      ) : event.startTime && (
                        <span>
                          {event.startTime}
                          {event.endTime && ` - ${event.endTime}`}
                        </span>
                      )}
                      {event.location && (
                        <span className="truncate">📍 {event.location}</span>
                      )}
                    </div>
                    {event.description && (
                      <p className="mt-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary line-clamp-2">
                        {event.description}
                      </p>
                    )}
                  </button>
                ))}
              </div>
            ) : (
              <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
                No events scheduled
              </p>
            )}
          </div>

          {/* Time Entries Section */}
          {timeEntries.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-3">
                <Clock className="w-4 h-4 text-accent-magenta dark:text-accent-cyan" />
                <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
                  Time Tracked
                </h3>
                {totalDuration > 0 && (
                  <span className="text-sm font-mono text-accent-magenta dark:text-accent-cyan">
                    {formatDuration(totalDuration, { showSeconds: false })}
                  </span>
                )}
              </div>
              <div className="space-y-2">
                {timeEntries.map((entry) => (
                  <button
                    key={entry.id}
                    onClick={() => onEditEntry?.(entry)}
                    className="w-full text-left p-3 rounded-button bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark hover:border-accent-magenta/50 dark:hover:border-accent-cyan/50 transition-all duration-standard ease-smooth"
                  >
                    <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                      {entry.description || 'No description'}
                    </div>
                    <div className="flex items-center justify-between mt-1 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      <span>
                        {formatTime(new Date(entry.startTime), '24h')}
                        {entry.endTime && ` - ${formatTime(new Date(entry.endTime), '24h')}`}
                      </span>
                      <span className="font-mono text-accent-magenta dark:text-accent-cyan">
                        {formatDuration(entry.duration, { showSeconds: false })}
                      </span>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Tasks Section */}
          {tasks.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-3">
                <CheckSquare className="w-4 h-4 text-accent-blue" />
                <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
                  Tasks Due
                </h3>
              </div>
              <div className="space-y-2">
                {tasks.map((task) => (
                  <button
                    key={task.id}
                    onClick={() => handleTaskClick(task)}
                    className="w-full text-left p-3 rounded-button bg-accent-blue/10 border border-accent-blue/20 hover:bg-accent-blue/20 transition-all duration-standard ease-smooth"
                  >
                    <div className="flex items-center gap-2">
                      <span className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {task.title}
                      </span>
                      <span className={`text-xs font-medium ${getPriorityColor(task.priority)}`}>
                        {task.priority}
                      </span>
                    </div>
                    <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
                      Status: {task.status.replace(/_/g, ' ')}
                    </div>
                    {task.description && (
                      <p className="mt-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary line-clamp-2">
                        {task.description}
                      </p>
                    )}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-border-light dark:border-border-dark">
          <button
            onClick={handleAddEvent}
            className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-accent-magenta hover:bg-accent-magenta-hover dark:bg-accent-cyan dark:hover:bg-accent-cyan-hover text-white rounded-button font-medium transition-all duration-standard ease-smooth"
          >
            <Plus className="w-4 h-4" />
            Add New Event
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * BackupOnboardingModal Component
 *
 * First-time onboarding modal for backup setup
 * - Step 1: Why Backup?
 * - Step 2: Choose Cloud Provider
 * - Step 3: Platform-Specific Instructions
 * - Step 4: Folder Picker (FSA API)
 * - Step 5: Reminder Preferences
 */

import { useState } from 'react';
import { Modal } from './Modal';
import { useThemeStore } from '../stores/useThemeStore';
import { autoSaveManager } from '../services/autoSave';
import { requestAutoSaveDirectory } from '../services/brainBackup';

interface BackupOnboardingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type CloudProvider = 'icloud' | 'google-drive' | 'onedrive' | 'proton-drive' | 'dropbox' | 'none';
type Platform = 'windows' | 'macos';
type ReminderPreference = 'every-session' | 'in-7-days' | 'never';

export function BackupOnboardingModal({ isOpen, onClose }: BackupOnboardingModalProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [selectedProvider, setSelectedProvider] = useState<CloudProvider | null>(null);
  const [platform, setPlatform] = useState<Platform>(() => {
    // Detect platform
    const userAgent = navigator.userAgent.toLowerCase();
    return userAgent.includes('mac') ? 'macos' : 'windows';
  });
  const [reminderPreference, setReminderPreference] = useState<ReminderPreference>('every-session');
  const [isSelecting, setIsSelecting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const totalSteps = 5;

  /**
   * Handle folder selection (Step 4)
   */
  const handleSelectFolder = async () => {
    setIsSelecting(true);
    setError(null);

    try {
      const dirHandle = await requestAutoSaveDirectory();

      // Update preferences
      updateBackupPreferences({
        hasBackupFolder: true,
        backupFolderPath: dirHandle.name,
        autoSaveEnabled: true,
      });

      // Enable auto-save
      await autoSaveManager.enableLocal(dirHandle);

      // Move to next step
      setCurrentStep(5);
    } catch (err) {
      if ((err as Error).name === 'AbortError') {
        setError('Folder selection cancelled. Please select a folder to continue.');
      } else {
        setError(`Error: ${(err as Error).message}`);
      }
    } finally {
      setIsSelecting(false);
    }
  };

  /**
   * Handle reminder preference save (Step 5)
   */
  const handleSaveReminder = () => {
    const nextReminderDate =
      reminderPreference === 'in-7-days'
        ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
        : null;

    updateBackupPreferences({
      reminderPreference,
      nextReminderDate,
    });

    onClose();
  };

  /**
   * Cloud provider instructions
   */
  const getInstructions = (provider: CloudProvider, platform: Platform) => {
    const instructions: Record<CloudProvider, Record<Platform, { title: string; steps: string[] }>> = {
      icloud: {
