                select the "Neuman Brain Backups" folder you created.
              </p>
            </div>

            {error && (
              <div className="bg-status-error/10 border border-status-error rounded-button p-4">
                <p className="text-sm text-status-error">{error}</p>
              </div>
            )}

            <button
              onClick={handleSelectFolder}
              disabled={isSelecting}
              className="w-full px-6 py-4 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-semibold text-lg transition-all duration-standard ease-smooth disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isSelecting ? 'Opening Folder Picker...' : '📁 Choose Backup Folder'}
            </button>

            <div className="flex gap-3 pt-4">
              <button
                onClick={() => setCurrentStep(3)}
                className="flex-1 px-4 py-2.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-border-light dark:hover:bg-border-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium transition-all duration-standard ease-smooth border border-border-light dark:border-border-dark"
              >
                Back
              </button>
            </div>
          </div>
        );
      }

      case 5: {
        // Reminder preferences
        return (
          <div className="space-y-4">
            <div className="text-center mb-6">
              <span className="text-6xl">✅</span>
            </div>

            <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary text-center">
              Auto-Save Enabled!
            </h2>

            <div className="bg-status-success/10 border border-status-success rounded-button p-4">
              <p className="text-sm text-status-success text-center">
                <strong>Your data is now automatically backed up every 30 seconds.</strong>
                <br />
                Backups are saved to your cloud-synced folder and will sync across all your devices.
              </p>
            </div>

            <div className="pt-4 space-y-3">
              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                Reminder Preference
              </h3>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                When should we remind you to check your backups?
              </p>

              <div className="space-y-2">
                {[
                  { id: 'every-session', label: 'Every session', description: 'Remind me each time I visit' },
                  { id: 'in-7-days', label: 'In 7 days', description: 'Remind me in a week' },
                  { id: 'never', label: 'Never', description: "Don't remind me again" },
                ].map((option) => (
                  <button
                    key={option.id}
                    onClick={() => setReminderPreference(option.id as ReminderPreference)}
                    className={`w-full p-4 rounded-button border-2 transition-all text-left ${
                      reminderPreference === option.id
                        ? 'border-accent-blue bg-accent-blue/10'
                        : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                    }`}
                  >
                    <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                      {option.label}
                    </div>
                    <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      {option.description}
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <button
              onClick={handleSaveReminder}
              className="w-full px-6 py-4 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-semibold text-lg transition-all duration-standard ease-smooth"
            >
              Finish Setup
            </button>

            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary text-center">
              You can always change these settings later in Settings → Backup & Sync
            </p>
          </div>
        );
      }

      default:
        return null;
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Setup Auto-Save Backup" maxWidth="2xl">
      {/* Progress Indicator */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            Step {currentStep > 2.5 ? Math.floor(currentStep) : currentStep} of {totalSteps}
          </span>
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {Math.round(((currentStep > 2.5 ? Math.floor(currentStep) : currentStep) / totalSteps) * 100)}% complete
          </span>
        </div>
        <div className="w-full bg-border-light dark:bg-border-dark rounded-full h-2">
          <div
            className="bg-accent-blue h-2 rounded-full transition-all duration-standard ease-smooth"
            style={{
              width: `${((currentStep > 2.5 ? Math.floor(currentStep) : currentStep) / totalSteps) * 100}%`,
            }}
          />
        </div>
      </div>

      {/* Step Content */}
      {renderStep()}
    </Modal>
  );
}

