import React, { useEffect, useRef, useCallback } from 'react';
import { useEscapeKey } from '../hooks/useEscapeKey';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  maxWidth?: 'sm' | 'md' | 'lg' | 'xl' | '2xl';
}

/**
 * Accessible Modal component with focus trapping
 * - Traps focus inside modal when open
 * - Returns focus to trigger element on close
 * - Handles escape key and backdrop click
 * - WCAG 2.1 AA compliant
 */
export const Modal: React.FC<ModalProps> = ({
  isOpen,
  onClose,
  title,
  children,
  maxWidth = 'md',
}) => {
  const modalRef = useRef<HTMLDivElement>(null);
  const previousActiveElement = useRef<HTMLElement | null>(null);

  // Handle escape key with high priority (z-9999)
  useEscapeKey({ enabled: isOpen, onEscape: onClose, priority: 9999 });

  // Focus trap - keep focus inside modal
  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (e.key !== 'Tab' || !modalRef.current) return;

    const focusableElements = modalRef.current.querySelectorAll<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    const firstFocusable = focusableElements[0];
    const lastFocusable = focusableElements[focusableElements.length - 1];

    if (e.shiftKey) {
      // Shift+Tab: if on first element, go to last
      if (document.activeElement === firstFocusable) {
        e.preventDefault();
        lastFocusable?.focus();
      }
    } else {
      // Tab: if on last element, go to first
      if (document.activeElement === lastFocusable) {
        e.preventDefault();
        firstFocusable?.focus();
      }
    }
  }, []);

  // Handle body overflow and focus management
  useEffect(() => {
    if (isOpen) {
      // Store currently focused element to return focus on close
      previousActiveElement.current = document.activeElement as HTMLElement;
      document.body.style.overflow = 'hidden';

      // Focus first focusable element in modal
      const timer = setTimeout(() => {
        const firstFocusable = modalRef.current?.querySelector<HTMLElement>(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        firstFocusable?.focus();
      }, 0);

      // Add focus trap listener
      document.addEventListener('keydown', handleKeyDown);

      return () => {
        clearTimeout(timer);
        document.removeEventListener('keydown', handleKeyDown);
        // Reset overflow and return focus when modal closes
        document.body.style.overflow = 'unset';
        previousActiveElement.current?.focus();
      };
    }
  }, [isOpen, handleKeyDown]);

  const maxWidthClasses = {
    sm: 'max-w-sm',
    md: 'max-w-md',
    lg: 'max-w-lg',
    xl: 'max-w-xl',
    '2xl': 'max-w-2xl',
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black bg-opacity-50"
        onClick={onClose}
      />

      {/* Modal */}
      <div
        ref={modalRef}
        className={`relative bg-surface-light dark:bg-surface-dark rounded-card shadow-modal ${maxWidthClasses[maxWidth]} w-full max-h-[90vh] flex flex-col`}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-title"
      >
        {/* Modal Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark flex-shrink-0">
          <h3
            id="modal-title"
            className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary truncate"
          >
            {title}
          </h3>

          {/* Close button */}
          <button
            onClick={onClose}
            className="p-1 text-text-light-secondary hover:text-text-light-primary dark:text-text-dark-secondary dark:hover:text-text-dark-primary transition-all duration-standard ease-smooth"
            aria-label="Close modal"
          >
            <span className="text-xl">×</span>
          </button>
        </div>

        {/* Modal Content */}
        <div className="p-4 overflow-y-auto overflow-x-hidden flex-1 min-h-0">
          {children}
        </div>
      </div>
    </div>
  );
};

/**
 * BackupOnboardingModal Component
 *
 * First-time onboarding modal for backup setup
 * - Step 1: Why Backup?
 * - Step 2: Choose Cloud Provider
 * - Step 3: Platform-Specific Instructions
 * - Step 4: Folder Picker (FSA API)
 * - Step 5: Reminder Preferences
 */

import { useState } from 'react';
import { Modal } from './Modal';
import { useThemeStore } from '../stores/useThemeStore';
import { autoSaveManager } from '../services/autoSave';
import { requestAutoSaveDirectory } from '../services/brainBackup';

interface BackupOnboardingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type CloudProvider = 'icloud' | 'google-drive' | 'onedrive' | 'proton-drive' | 'dropbox' | 'none';
type Platform = 'windows' | 'macos';
type ReminderPreference = 'every-session' | 'in-7-days' | 'never';

export function BackupOnboardingModal({ isOpen, onClose }: BackupOnboardingModalProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [selectedProvider, setSelectedProvider] = useState<CloudProvider | null>(null);
  const [platform, setPlatform] = useState<Platform>(() => {
    // Detect platform
    const userAgent = navigator.userAgent.toLowerCase();
    return userAgent.includes('mac') ? 'macos' : 'windows';
  });
  const [reminderPreference, setReminderPreference] = useState<ReminderPreference>('every-session');
  const [isSelecting, setIsSelecting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const totalSteps = 5;

  /**
   * Handle folder selection (Step 4)
   */
  const handleSelectFolder = async () => {
    setIsSelecting(true);
    setError(null);

    try {
      const dirHandle = await requestAutoSaveDirectory();

      // Update preferences
      updateBackupPreferences({
        hasBackupFolder: true,
        backupFolderPath: dirHandle.name,
        autoSaveEnabled: true,
      });

      // Enable auto-save
      await autoSaveManager.enableLocal(dirHandle);

      // Move to next step
      setCurrentStep(5);
    } catch (err) {
      if ((err as Error).name === 'AbortError') {
        setError('Folder selection cancelled. Please select a folder to continue.');
      } else {
        setError(`Error: ${(err as Error).message}`);
      }
    } finally {
      setIsSelecting(false);
    }
  };

  /**
   * Handle reminder preference save (Step 5)
   */
  const handleSaveReminder = () => {
    const nextReminderDate =
      reminderPreference === 'in-7-days'
        ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
        : null;

    updateBackupPreferences({
      reminderPreference,
      nextReminderDate,
    });

    onClose();
  };

  /**
   * Cloud provider instructions
   */
  const getInstructions = (provider: CloudProvider, platform: Platform) => {
    const instructions: Record<CloudProvider, Record<Platform, { title: string; steps: string[] }>> = {
      icloud: {
        windows: {
          title: 'iCloud Drive (Windows)',
          steps: [
            'Install iCloud for Windows from the Microsoft Store',
