                </p>
              </div>
            </div>

            <div className="flex gap-3 pt-4">
              <button
                onClick={onClose}
                className="flex-1 px-4 py-2.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-border-light dark:hover:bg-border-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium transition-all duration-standard ease-smooth border border-border-light dark:border-border-dark"
              >
                Skip for Now
              </button>
              <button
                onClick={() => setCurrentStep(2)}
                className="flex-1 px-4 py-2.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-medium transition-all duration-standard ease-smooth"
              >
                Continue
              </button>
            </div>
          </div>
        );

      case 2:
        return (
          <div className="space-y-4">
            <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
              Choose Your Cloud Provider
            </h2>

            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Select the cloud storage service you use (or want to use):
            </p>

            <div className="grid grid-cols-1 gap-3">
              {[
                { id: 'icloud', name: 'iCloud Drive', icon: '☁️', description: 'Apple (5GB free)' },
                { id: 'google-drive', name: 'Google Drive', icon: '📁', description: 'Google (15GB free)' },
                { id: 'onedrive', name: 'OneDrive', icon: '☁️', description: 'Microsoft (5GB free)' },
                { id: 'proton-drive', name: 'Proton Drive', icon: '🔒', description: 'Proton (1GB free, encrypted)' },
                { id: 'dropbox', name: 'Dropbox', icon: '📦', description: 'Dropbox (2GB free)' },
              ].map((provider) => (
                <button
                  key={provider.id}
                  onClick={() => setSelectedProvider(provider.id as CloudProvider)}
                  className={`p-4 rounded-button border-2 transition-all text-left ${
                    selectedProvider === provider.id
                      ? 'border-accent-blue bg-accent-blue/10'
                      : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <span className="text-2xl">{provider.icon}</span>
                    <div>
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                        {provider.name}
                      </div>
                      <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                        {provider.description}
                      </div>
                    </div>
                  </div>
                </button>
              ))}

              <button
                onClick={() => setSelectedProvider('none')}
                className={`p-4 rounded-button border-2 transition-all text-left ${
                  selectedProvider === 'none'
                    ? 'border-accent-blue bg-accent-blue/10'
                    : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                }`}
              >
                <div className="flex items-center gap-3">
                  <span className="text-2xl">❓</span>
                  <div>
                    <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                      I don't have one
                    </div>
                    <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      Show me free options
