                },
                {
                  name: 'Dropbox',
                  storage: '2GB free',
                  url: 'https://dropbox.com',
                  pros: 'Reliable, widely supported',
                },
              ].map((provider) => (
                <div
                  key={provider.name}
                  className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button border border-border-light dark:border-border-dark"
                >
                  <div className="flex items-start justify-between mb-2">
                    <div>
                      <div className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                        {provider.name}
                      </div>
                      <div className="text-sm text-accent-blue">{provider.storage}</div>
                    </div>
                    <a
                      href={provider.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="px-3 py-1.5 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm rounded-button transition-all duration-standard ease-smooth"
                    >
                      Sign Up →
                    </a>
                  </div>
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                    {provider.pros}
                  </p>
                </div>
              ))}
            </div>

            <div className="bg-status-info/10 border border-status-info rounded-button p-4">
              <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
                <strong>💡 Tip:</strong> After signing up, download the desktop app for automatic syncing. Then come
                back and select the provider in Step 2.
              </p>
            </div>

            <div className="flex gap-3 pt-4">
              <button
                onClick={() => {
                  setSelectedProvider(null);
                  setCurrentStep(2);
                }}
                className="flex-1 px-4 py-2.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-medium transition-all duration-standard ease-smooth"
              >
                ← Back to Providers
              </button>
            </div>
          </div>
        );
      }

      case 3: {
        // Platform-specific instructions
        if (!selectedProvider || selectedProvider === 'none') {
          setCurrentStep(2);
          return null;
        }

        const instructions = getInstructions(selectedProvider, platform);

        return (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
                Setup Instructions
              </h2>
              <div className="flex gap-2">
                <button
                  onClick={() => setPlatform('windows')}
                  className={`px-3 py-1.5 text-sm rounded-button transition-all duration-standard ease-smooth ${
                    platform === 'windows'
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                  }`}
                >
                  Windows
                </button>
                <button
                  onClick={() => setPlatform('macos')}
                  className={`px-3 py-1.5 text-sm rounded-button transition-all duration-standard ease-smooth ${
                    platform === 'macos'
                      ? 'bg-accent-blue text-white'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                  }`}
                >
                  macOS
                </button>
              </div>
            </div>

            <div className="bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button p-4">
              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                {instructions.title}
              </h3>
              <ol className="space-y-2 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                {instructions.steps.map((step, index) => (
                  <li key={index} className="flex gap-3">
                    <span className="flex-shrink-0 font-semibold text-accent-blue">{index + 1}.</span>
                    <span>{step}</span>
                  </li>
                ))}
              </ol>
            </div>

            <div className="bg-status-warning/10 border border-status-warning rounded-button p-4">
              <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
                <strong>⚠️ Important:</strong> Make sure the desktop app is installed and syncing before continuing.
                The folder you select must be inside your cloud-synced folder.
              </p>
            </div>

            <div className="flex gap-3 pt-4">
              <button
                onClick={() => setCurrentStep(2)}
                className="flex-1 px-4 py-2.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-border-light dark:hover:bg-border-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium transition-all duration-standard ease-smooth border border-border-light dark:border-border-dark"
              >
                Back
              </button>
              <button
                onClick={() => setCurrentStep(4)}
                className="flex-1 px-4 py-2.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-medium transition-all duration-standard ease-smooth"
              >
                I'm Ready
              </button>
            </div>
          </div>
        );
      }

      case 4: {
        // Folder picker
        return (
          <div className="space-y-4">
            <div className="text-center mb-6">
              <span className="text-6xl">📁</span>
            </div>

            <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary text-center">
              Select Your Backup Folder
            </h2>

            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center">
              Click the button below to choose the folder where backups will be saved.
            </p>

            <div className="bg-status-info/10 border border-status-info rounded-button p-4">
              <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
                <strong>💡 Tip:</strong> Navigate to your cloud-synced folder (iCloud Drive, Google Drive, etc.) and
                select the "Neuman Brain Backups" folder you created.
              </p>
            </div>

            {error && (
              <div className="bg-status-error/10 border border-status-error rounded-button p-4">
                <p className="text-sm text-status-error">{error}</p>
              </div>
            )}

            <button
              onClick={handleSelectFolder}
              disabled={isSelecting}
              className="w-full px-6 py-4 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-semibold text-lg transition-all duration-standard ease-smooth disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isSelecting ? 'Opening Folder Picker...' : '📁 Choose Backup Folder'}
            </button>

            <div className="flex gap-3 pt-4">
              <button
                onClick={() => setCurrentStep(3)}
                className="flex-1 px-4 py-2.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-border-light dark:hover:bg-border-dark text-text-light-primary dark:text-text-dark-primary rounded-button font-medium transition-all duration-standard ease-smooth border border-border-light dark:border-border-dark"
              >
                Back
              </button>
            </div>
          </div>
        );
      }

      case 5: {
        // Reminder preferences
        return (
          <div className="space-y-4">
            <div className="text-center mb-6">
              <span className="text-6xl">✅</span>
            </div>

            <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary text-center">
              Auto-Save Enabled!
            </h2>

            <div className="bg-status-success/10 border border-status-success rounded-button p-4">
              <p className="text-sm text-status-success text-center">
                <strong>Your data is now automatically backed up every 30 seconds.</strong>
                <br />
                Backups are saved to your cloud-synced folder and will sync across all your devices.
              </p>
            </div>

            <div className="pt-4 space-y-3">
              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                Reminder Preference
              </h3>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                When should we remind you to check your backups?
              </p>

              <div className="space-y-2">
                {[
                  { id: 'every-session', label: 'Every session', description: 'Remind me each time I visit' },
                  { id: 'in-7-days', label: 'In 7 days', description: 'Remind me in a week' },
                  { id: 'never', label: 'Never', description: "Don't remind me again" },
                ].map((option) => (
                  <button
                    key={option.id}
                    onClick={() => setReminderPreference(option.id as ReminderPreference)}
                    className={`w-full p-4 rounded-button border-2 transition-all text-left ${
                      reminderPreference === option.id
                        ? 'border-accent-blue bg-accent-blue/10'
                        : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                    }`}
                  >
                    <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                      {option.label}
                    </div>
                    <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                      {option.description}
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <button
              onClick={handleSaveReminder}
              className="w-full px-6 py-4 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button font-semibold text-lg transition-all duration-standard ease-smooth"
            >
              Finish Setup
            </button>

            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary text-center">
              You can always change these settings later in Settings → Backup & Sync
            </p>
          </div>
        );
      }

      default:
        return null;
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Setup Auto-Save Backup" maxWidth="2xl">
      {/* Progress Indicator */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            Step {currentStep > 2.5 ? Math.floor(currentStep) : currentStep} of {totalSteps}
          </span>
          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {Math.round(((currentStep > 2.5 ? Math.floor(currentStep) : currentStep) / totalSteps) * 100)}% complete
          </span>
        </div>
        <div className="w-full bg-border-light dark:bg-border-dark rounded-full h-2">
          <div
            className="bg-accent-blue h-2 rounded-full transition-all duration-standard ease-smooth"
            style={{
              width: `${((currentStep > 2.5 ? Math.floor(currentStep) : currentStep) / totalSteps) * 100}%`,
            }}
          />
        </div>
      </div>

      {/* Step Content */}
      {renderStep()}
    </Modal>
  );
}

