        // Folder picker
        return (
          <div className="space-y-3">
            <div className="text-center mb-4">
              <span className="text-5xl">📁</span>
            </div>

            <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary text-center">
